// Daily summary of delivery orders
const items = $input.all();
const today = new Date();
const todayStr = today.toISOString().split('T')[0]; // YYYY-MM-DD

// Filter today's orders (by created_at)
const todayOrders = items.filter(item => {
  const created = item.json.created_at || '';
  return created.startsWith(todayStr);
});

const total = todayOrders.length;
const completed = todayOrders.filter(i => i.json.status === 'Оформлен').length;
const errors = todayOrders.filter(i => i.json.status === 'Ошибка').length;
const inProgress = todayOrders.filter(i => ['Новый', 'Расчёт', 'Рассчитан', 'Оформляется'].includes(i.json.status)).length;

// Carrier breakdown
const yandex = todayOrders.filter(i => (i.json.chosen_carrier || '').includes('Яндекс')).length;
const ozon = todayOrders.filter(i => (i.json.chosen_carrier || '').includes('Озон')).length;

// Average price
const prices = todayOrders
  .map(i => parseFloat(i.json.best_price))
  .filter(p => !isNaN(p) && p > 0);
const avgPrice = prices.length > 0 
  ? Math.round(prices.reduce((a, b) => a + b, 0) / prices.length) 
  : 0;

// Total spent
const totalSpent = prices.reduce((a, b) => a + b, 0);

const dateFormatted = today.toLocaleDateString('ru-RU', { 
  timeZone: 'Asia/Krasnoyarsk',
  day: '2-digit', 
  month: '2-digit', 
  year: 'numeric' 
});

const text = `📊 Итого за ${dateFormatted}:\n\n` +
  `📦 Заказов: ${total}\n` +
  `✅ Оформлено: ${completed}\n` +
  `⏳ В работе: ${inProgress}\n` +
  `❌ Ошибок: ${errors}\n\n` +
  `🚚 Яндекс: ${yandex} | Озон: ${ozon}\n` +
  `💰 Средняя цена: ${avgPrice}₽\n` +
  `💵 Всего: ${Math.round(totalSpent)}₽`;

return [{ json: { text, total, completed, errors } }];
